def solve(*args):
    import json
    import os

    # args expected: problemId (str)
    if len(args) != 1:
        raise ValueError("Expected exactly one argument: problemId")
    problemId = args[0]
    if not isinstance(problemId, str):
        raise TypeError("problemId must be a string")

    # Load problems.json
    data_path = os.path.join("data", "problems.json")
    if not os.path.isfile(data_path):
        # If file missing, simulate 404 error JSON
        return {"status": 404, "error": "Problem data not found"}

    with open(data_path, "r", encoding="utf-8") as f:
        problems = json.load(f)

    # Find problem by problemId
    problem = None
    for p in problems:
        if str(p.get("problemId")) == problemId:
            problem = p
            break

    if problem is None:
        # Return 404 JSON error if problem not found
        return {"status": 404, "error": "Problem not found"}

    # Aggregate component metadata:
    # language counts, status counts, max points
    components = problem.get("components", [])
    language_counts = {}
    status_counts = {}
    max_points = 0

    for comp in components:
        lang = comp.get("language")
        if lang:
            language_counts[lang] = language_counts.get(lang, 0) + 1

        status = comp.get("status")
        if status:
            status_counts[status] = status_counts.get(status, 0) + 1

        points = comp.get("points")
        if isinstance(points, (int, float)) and points > max_points:
            max_points = points

    # Compose response JSON
    response = {
        "problemId": problemId,
        "componentStatistics": {
            "languageCounts": language_counts,
            "statusCounts": status_counts,
            "maxPoints": max_points,
        },
    }
    return response
